package com.example.lessondesign.dao; import com.example.lessondesign.bean.Course; import org.apache.ibatis.annotations.*; import java.util.*; @Mapper public interface CourseDao { @Select("SELECT * FROM course") List<Course> findAll(); @Select("SELECT * FROM course WHERE id=#{id}") Course findById(@Param("id") int id); @Select("SELECT COUNT(*)>0 FROM course WHERE id=#{id}") boolean existsById(@Param("id") int id); }